INSERT INTO chatcit_knowledge (keyword, response, picture_url, usage_count) VALUES ('Part Vi Policies And Guidelines', '111                        PART VI. POLICIES AND GUIDELINES  ON EDUCATIONAL TRIPS AND TOURS', '/handbook.pdf#page=123', 0);
INSERT INTO chatcit_knowledge (keyword, response, picture_url, usage_count) VALUES ('Bsu Hymn', 'BSU HYMN  Lyrics by Rolando R. Gaspar  Music by Herminio M. Suarez        Bulacan State University  Thy name will always be  You prepare us in life’s journey  For the service of God and society  You nurture our minds in diversity  Oh great is thy faculty;      BSU your fame and beauty  We’ll uphold ‘til eternity  Creative thoughts and skillful hands  To us your best gift of time  We will share our best to humanity  For our nation’s prosperity;      Your vision is now our mission  We shall lead the next generation  The values ingrained in our hearts  We will treasure, we’ll impart  Bulacan State University  Forever we’ll honor thee!', '/handbook.pdf#page=152', 0);
INSERT INTO chatcit_knowledge (keyword, response, picture_url, usage_count) VALUES ('Bsu March', 'BSU MARCH  Lyrics by Francisca P. Enriquez  Music by Augusto Miranda      Alma Mater, a prayer from the teachers  You enlightened our minds to success  Hear a song from the hearts of the masters  Of the compass, slide rule and pen      Alma Mater, your fame  We shall carry it everywhere  We shall strive for the glory of your name  For your honors, O BSU dear      We shall leave traces on the stars  We shall follow your torch to our goal  For our country we will struggle  Pledge to do our share in life’s gain      BSU when we part  Aware and willing  Your sons in flight of time  We shall hail thee with praises and cheer  My BSU dear', '/handbook.pdf#page=153', 0);
